#!/usr/bin/env python3
"""
kaching-tell — live-hardening patch (run after the earlier detection fix)
Applies 3 safety changes, embedded as base64 so nothing can be corrupted:
  1. package.json  - remove dead 'replay' script (file was deleted)
  2. writer.js     - atomic ledger write (temp+rename) so a crash mid-write
                     can't corrupt ledger.json / lose your on-chain proof
  3. index.js      - global crash guards so a transient SSE/RPC error can't
                     kill the agent mid-match
Safe to re-run. Usage: python3 fix_kaching_tell_live.py [/path/to/repo]
"""
import base64, os, sys, shutil, subprocess, datetime
FILES = {
    'package.json': "",
    'src/ledger/writer.js': "",
    'src/index.js': "",
}

def find_repo(argv):
    if len(argv) > 1: return os.path.abspath(argv[1])
    here = os.path.abspath(os.path.dirname(__file__))
    for c in (here, os.path.expanduser("~/kaching-tell"), os.getcwd()):
        if os.path.isfile(os.path.join(c, "package.json")) and os.path.isdir(os.path.join(c, "src")):
            return c
    return here

def main():
    repo = find_repo(sys.argv)
    if not os.path.isdir(os.path.join(repo, "src")):
        print("ERROR: run inside the kaching-tell repo, or pass its path."); sys.exit(1)
    stamp = datetime.datetime.now().strftime("%Y%m%d-%H%M%S")
    backup = os.path.join(repo, ".fix2-backup-" + stamp); os.makedirs(backup, exist_ok=True)
    print("Repo:   " + repo); print("Backup: " + backup)
    for rel, b64 in FILES.items():
        dest = os.path.join(repo, rel); os.makedirs(os.path.dirname(dest), exist_ok=True)
        if os.path.exists(dest):
            shutil.copy2(dest, os.path.join(backup, rel.replace("/", "__")))
        open(dest, "wb").write(base64.b64decode(b64))
        print("  wrote " + rel)
    node = shutil.which("node")
    if node:
        print("\nSyntax check:")
        for rel in ("src/index.js", "src/ledger/writer.js"):
            r = subprocess.run([node,"-c",os.path.join(repo,rel)], capture_output=True, text=True)
            print(("  OK   " if r.returncode==0 else "  FAIL ")+rel+("" if r.returncode==0 else "\n"+r.stderr))
    print("\nDone. Now:  git add -A && git commit -m \"Harden for live match\" && git push")
    print("Originals saved in: " + backup)

if __name__ == "__main__": main()
